import React from "react";
import { Navigate, Outlet, Route, Routes } from "react-router-dom";
import "./App.css";

import useAuth from "./hooks/useAuth";

import HomePage from "./pages/HomePage";
import DownloadPage from "./pages/DownloadPage";

import LoginPage from "./components/5_Auth/LoginPage";
import SignupPage from "./components/5_Auth/SignupPage";

import DashboardLayout from "./components/3_Layout/DashboardLayout";
import Dashboard from "./components/6_Dashboard/Dashboard";
import ChatHistory from "./components/6_Dashboard/ChatHistory";
import SecuritySettings from "./components/6_Dashboard/SecuritySettings";
import Reports from "./components/6_Dashboard/Reports";
import PersonalInfo from "./components/6_Dashboard/PersonalInfo";
import PersonalSettings from "./components/6_Dashboard/PersonalSettings";

import MyPage from "./components/7_MyPage/MyPage";
import AdminPage from "./components/8_AdminPage/AdminPage";

const PrivateRoute = () => {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? <Outlet /> : <Navigate to="/login" replace />;
};

const AdminRoute = () => {
  const { isAdmin } = useAuth();
  return isAdmin ? <Outlet /> : <Navigate to="/" replace />;
};

const NotFoundPage = () => {
  return (
    <div
      style={{
        minHeight: "100vh",
        display: "grid",
        placeItems: "center",
        background: "linear-gradient(180deg, #fffafc 0%, #f7f8ff 100%)",
        padding: "24px",
      }}
    >
      <div
        style={{
          width: "min(560px, 100%)",
          background: "rgba(255,255,255,0.92)",
          border: "1px solid #e7eaf6",
          borderRadius: "28px",
          padding: "40px 28px",
          textAlign: "center",
          boxShadow: "0 18px 44px rgba(104, 116, 200, 0.12)",
        }}
      >
        <div style={{ fontSize: "3rem", marginBottom: "12px" }}>🐰</div>
        <h1 style={{ margin: "0 0 12px", fontSize: "2rem", color: "#1f2333" }}>
          페이지를 찾을 수 없어요
        </h1>
        <p style={{ margin: 0, color: "#5f667a", lineHeight: 1.8 }}>
          요청한 페이지가 없거나 이동되었어요.
          <br />
          메이티 홈으로 돌아가 다시 시작해볼까요?
        </p>

        <a
          href="/"
          style={{
            display: "inline-block",
            marginTop: "24px",
            padding: "14px 20px",
            borderRadius: "999px",
            background:
              "linear-gradient(135deg, #7c8cff 0%, #9aa6ff 44%, #ffb7d5 100%)",
            color: "#fff",
            fontWeight: 800,
          }}
        >
          홈으로 이동
        </a>
      </div>
    </div>
  );
};

function App() {
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/download" element={<DownloadPage />} />

      <Route path="/login" element={<LoginPage />} />
      <Route path="/signup" element={<SignupPage />} />

      <Route element={<PrivateRoute />}>
        <Route path="/mypage" element={<MyPage />} />

        <Route path="/dashboard" element={<DashboardLayout />}>
          <Route index element={<Dashboard />} />
          <Route path="chat-history" element={<ChatHistory />} />
          <Route path="security" element={<SecuritySettings />} />
          <Route path="reports" element={<Reports />} />
          <Route path="personal-info" element={<PersonalInfo />} />
          <Route path="settings" element={<PersonalSettings />} />
        </Route>
      </Route>

      <Route element={<AdminRoute />}>
        <Route path="/admin" element={<AdminPage />} />
      </Route>

      <Route path="*" element={<NotFoundPage />} />
    </Routes>
  );
}

export default App;
